INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Primer Grado', 'Formación Ciudadana', '1. Valora su identidad personal, familiar, de grupo social, étnica y cultural, así como su participación, la de sus padres y compañeras (os) en el desarrollo de actividades en la familia y en el aula.', ARRAY['1.1. Se respeta a sí mismo o a sí misma, a su familia y a su grupo social.', '1.2. Participa con responsabilidad en las actividades del hogar y del aula.', '1.3. Es solidario, cooperativo y equitativo en las actividades que realiza, en la familia y en el aula.', '1.4. Manifiesta su autoestima y aprecio por los y las demás.', '1.5. Se identifica con orgullo con respecto a su familia, grupo social, étnico y cultural.']),
('Primer Grado', 'Formación Ciudadana', '2. Evidencia equidad y buen trato en sus relaciones interpersonales como niña o niño en la vida familiar y escolar.', ARRAY['2.1. Participa con autonomía en actividades en la escuela.', '2.2. Trata con equidad a niñas, niños, maestras y maestros.', '2.3. Defiende el derecho a dar y recibir un trato social y legal basado en la equidad y la justicia social.']),
('Primer Grado', 'Formación Ciudadana', '3. Comparte responsabilidades, deberes y obligaciones en el aula.', ARRAY['3.1. Participa en la organización de actividades de aula.', '3.2. Propone soluciones a los problemas en el aula.', '3.3. Comparte opiniones en la toma de decisiones en el aula.']),
('Primer Grado', 'Formación Ciudadana', '4. Participa en la discusión y búsqueda de solución a los problemas y conflictos en el aula.', ARRAY['4.1. Aplica los aportes, las opiniones y los consejos que recibe, a la solución de problemas.', '4.2. Aplica técnicas comunicativas para afrontar conflictos y resolver problemas en el aula y en la escuela.']),
('Primer Grado', 'Formación Ciudadana', '5. Interpreta el presente de su comunidad con base en los hechos históricos, testimonios y actores destacados.', ARRAY['5.1. Identifica hechos históricos importantes de la comunidad.', '5.2. Identifica a los actores destacados de los hechos históricos de su comunidad.', '5.3. Identifica los lugares de importancia histórica de la comunidad.']);
